#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
===============================================

This script provides utilities for managing Python dependency lock files
to ensure consistent versions across development and production environments.

Features:
- Generate requirements.txt with hashes
- Update dependencies
- Validate lock files
- Support for both pip and Poetry workflows
"""

import subprocess
import sys
import os
import hashlib
import re
from pathlib import Path
from typing import List, Dict, Optional

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        
    def generate_requirements_with_hashes(self) -> None:
        """Generate requirements.txt with hashes using pip-compile"""
        try:
            subprocess.run([
                sys.executable, "-m", "pip-compile", 
                "--generate-hashes", 
                "--output-file", str(self.requirements_file),
                "pyproject.toml"
            ], check=True, capture_output=True)
            print("✓ Generated requirements.txt with hashes")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to generate requirements.txt: {e}")
            sys.exit(1)
    
    def update_dependencies(self, upgrade_all: bool = False) -> None:
        """Update dependencies in requirements.txt"""
        if not self.requirements_file.exists():
            print("⚠ requirements.txt not found, generating new one")
            self.generate_requirements_with_hashes()
            return
            
        try:
            cmd = [
                sys.executable, "-m", "pip-compile", 
                "--upgrade",
                "--generate-hashes",
                "--output-file", str(self.requirements_file),
                str(self.requirements_file)
            ]
            
            if upgrade_all:
                cmd.append("--upgrade-all")
                
            subprocess.run(cmd, check=True, capture_output=True)
            print("✓ Dependencies updated successfully")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to update dependencies: {e}")
            sys.exit(1)
    
    def generate_poetry_lock(self) -> None:
        """Generate poetry.lock file from pyproject.toml"""
        try:
            subprocess.run([
                "poetry", "lock", "--no-update"
            ], cwd=self.project_root, check=True, capture_output=True)
            print("✓ Generated poetry.lock file")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to generate poetry.lock: {e}")
            sys.exit(1)
    
    def update_poetry_lock(self) -> None:
        """Update poetry.lock file with latest versions"""
        try:
            subprocess.run([
                "poetry", "lock", "--update"
            ], cwd=self.project_root, check=True, capture_output=True)
            print("✓ Updated poetry.lock file")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to update poetry.lock: {e}")
            sys.exit(1)
    
    def validate_lock_files(self) -> bool:
        """Validate that lock files are consistent"""
        errors = []
        
        if self.requirements_file.exists():
            try:
                with open(self.requirements_file, 'r') as f:
                    content = f.read()
                    if not re.search(r'--hash=sha256:', content):
                        errors.append("requirements.txt missing hashes")
            except Exception as e:
                errors.append(f"Error reading requirements.txt: {e}")
        
        if self.poetry_lock_file.exists():
            try:
                with open(self.poetry_lock_file, 'r') as f:
                    content = f.read()
                    if '[[package]]' not in content:
                        errors.append("poetry.lock appears malformed")
            except Exception as e:
                errors.append(f"Error reading poetry.lock: {e}")
        
        if errors:
            print("✗ Validation errors:")
            for error in errors:
                print(f"  - {error}")
            return False
            
        print("✓ Lock files validated successfully")
        return True
    
    def install_from_requirements(self) -> None:
        """Install dependencies from requirements.txt"""
        if not self.requirements_file.exists():
            print("⚠ requirements.txt not found")
            return
            
        try:
            subprocess.run([
                sys.executable, "-m", "pip", "install", 
                "--requirement", str(self.requirements_file)
            ], check=True, capture_output=True)
            print("✓ Installed dependencies from requirements.txt")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to install dependencies: {e}")
            sys.exit(1)
    
    def install_from_poetry(self) -> None:
        """Install dependencies from poetry.lock"""
        if not self.poetry_lock_file.exists():
            print("⚠ poetry.lock not found")
            return
            
        try:
            subprocess.run([
                "poetry", "install"
            ], cwd=self.project_root, check=True, capture_output=True)
            print("✓ Installed dependencies from poetry.lock")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to install dependencies: {e}")
            sys.exit(1)
    
    def get_dependency_info(self) -> Dict[str, str]:
        """Get current dependency versions"""
        info = {}
        
        if self.requirements_file.exists():
            try:
                with open(self.requirements_file, 'r') as f:
                    for line in f:
                        if line.strip() and not line.startswith('#'):
                            if '==' in line:
                                package, version = line.split('==', 1)
                                info[package.strip()] = version.strip()
            except Exception as e:
                print(f"Error reading requirements.txt: {e}")
        
        return info

def main():
    """Main function to handle command line arguments"""
    dm = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [command]")
        print("Commands:")
        print("  generate          - Generate requirements.txt with hashes")
        print("  update            - Update dependencies")
        print("  update-all        - Update all dependencies")
        print("  validate          - Validate lock files")
        print("  install           - Install from requirements.txt")
        print("  install-poetry    - Install from poetry.lock")
        print("  info              - Show current dependency info")
        sys.exit(1)
    
    command = sys.argv[1]
    
    if command == "generate":
        dm.generate_requirements_with_hashes()
    elif command == "update":
        dm.update_dependencies()
    elif command == "update-all":
        dm.update_dependencies(upgrade_all=True)
    elif command == "validate":
        dm.validate_lock_files()
    elif command == "install":
        dm.install_from_requirements()
    elif command == "install-poetry":
        dm.install_from_poetry()
    elif command == "info":
        info = dm.get_dependency_info()
        for package, version in info.items():
            print(f"{package}=={version}")
    else:
        print(f"Unknown command: {command}")
        sys.exit(1)

if __name__ == "__main__":
    main()